    { name: { en: 'Kidney Beans', ro: 'fasole rosie', ru: 'красная фасоль', es: 'frijoles rojos' }, measure: '400g' },
    { name: { en: 'Basmati Rice', ro: 'orez basmati', ru: 'рис басмати', es: 'arroz basmati' }, measure: 'to serve' }
