    { name: { en: 'Red Onions', ro: 'ceapa rosie', ru: 'красный лук', es: 'cebollas moradas' }, measure: '1 sliced' },
    { name: { en: 'Yogurt', ro: 'iaurt', ru: 'йогурт', es: 'yogur' }, measure: 'Small pack' }
