    name: { en: 'Kvæfjord Cake “Verdens Beste” (World’s Best Cake)', ro: 'Kvæfjord Cake “Verdens Beste” (World’s Best Cake)', ru: 'Kvæfjord Cake “Verdens Beste” (World’s Best Cake)', es: 'Kvæfjord Cake “Verdens Beste” (World’s Best Cake)' },
